const body = $input.first().json.body ?? $input.first().json;
const { seq_step_id, sequence_id, step_position, step_name, scheduled_date, duration_minutes, notes, is_lab_pending = false, cascade_mode = 'none', cascade_days = 0 } = body;

if (!sequence_id)   throw new Error('sequence_id is required');
if (!step_position) throw new Error('step_position is required');

const isUpdate = !!seq_step_id;
if (!isUpdate && !step_name) throw new Error('step_name is required when creating a new step');

const cascadeDays = parseInt(cascade_days, 10) || 0;
const doCascade   = cascade_mode === 'shift_all' && cascadeDays !== 0;

return [{ json: {
  seq_step_id:      seq_step_id ? parseInt(seq_step_id, 10) : null,
  sequence_id:      parseInt(sequence_id, 10),
  step_position:    parseInt(step_position, 10),
  step_name:        step_name || null,
  scheduled_date:   scheduled_date || null,
  duration_minutes: duration_minutes ? parseInt(duration_minutes, 10) : null,
  notes:            notes || null,
  is_lab_pending:   !!is_lab_pending,
  cascade_mode,
  cascade_days:     cascadeDays,
  doCascade,
  isUpdate,
} }];

const p = $json;
const nameClause  = p.step_name    ? `, step_name = '${p.step_name.replace(/'/g, "''")}'` : '';
const dateClause  = p.scheduled_date ? `, scheduled_date = '${p.scheduled_date}'` : '';
const durClause   = p.duration_minutes != null ? `, duration_minutes = ${p.duration_minutes}` : '';
const notesClause = p.notes != null   ? `, notes = '${p.notes.replace(/'/g, "''")}'` : '';

const updateSQL = `
  UPDATE treatment_seq_steps
  SET
    is_lab_pending = ${p.is_lab_pending}
    ${nameClause}
    ${dateClause}
    ${durClause}
    ${notesClause},
    updated_at = NOW()
  WHERE id = ${p.seq_step_id}
    AND sequence_id = ${p.sequence_id}
  RETURNING id
`;
return [{ json: { ...p, updateSQL } }];

const p = $json;
const dateVal  = p.scheduled_date   ? `'${p.scheduled_date}'`                    : 'NULL';
const durVal   = p.duration_minutes  ? p.duration_minutes                          : 'NULL';
const notesVal = p.notes             ? `'${p.notes.replace(/'/g, "''")}'`         : 'NULL';

const insertSQL = `
  INSERT INTO treatment_seq_steps
    (sequence_id, step_position, step_name, scheduled_date, duration_minutes, notes, is_lab_pending)
  VALUES
    (${p.sequence_id}, ${p.step_position}, '${p.step_name.replace(/'/g, "''")}',
     ${dateVal}, ${durVal}, ${notesVal}, ${p.is_lab_pending})
  RETURNING id
`;
return [{ json: { ...p, insertSQL } }];
